import Header from "./components/main/header";
import Sidebar from "./components/main/sidebar";
import DashboardContent from "./components/main/dashboard-content";
import MyTask from "./components/main/my-task";
import VitalTask from "./components/main/vitals-tasks";
import TaskCategories from "./components/main/categories";
import CreateCategory from "./components/main/create-category";
import { useState } from "react";

const testTask = {
  title: "Attend Nischal's Birthday Party",
  fullTitle: "Birthday Celebration for Nischal",
  objective: "Celebrate Nischal's birthday and have fun with friends.",
  description:
    "Buy gifts on the way and pick up cake from the bakery. (6 PM | Fresh Elements).....",
  priority: "Moderate",
  status: "Not Started",
  date: "20/06/2023",
  deadline: "6:00 PM Today",
  image: "images/task_image1.png",
  notes: ["Check bakery opening hours", "Buy wrapping paper"],
};

const Main = () => {
  const [activeId, setActiveId] = useState(1);
  const [isCreatingCategory, setIsCreatingCategory] = useState(false);
  const [modalConfig, setModalConfig] = useState({
    isOpen: false,
    type: null,
    categoryId: null,
    item: null,
  });

  // Відкриття для редагування
  const openEditModal = (categoryId, item) => {
    setModalConfig({
      isOpen: true,
      type: "edit",
      categoryId,
      item,
      titlePrefix: "Edit",
      titleMain: "Item Name",
      submitLabel: "Update",
      initialValue: item.name,
    });
  };

  // Відкриття для підтвердження видалення
  const openDeleteModal = (categoryId, item) => {
    setModalConfig({
      isOpen: true,
      type: "delete",
      categoryId,
      item,
      titlePrefix: "Delete",
      titleMain: "Item",
      submitLabel: "Delete",
      initialValue: item.name, // Щоб юзер бачив, що видаляє
      inputLabel: "Are you sure you want to delete?",
    });
  };
  const [categories, setCategories] = useState([
    {
      id: "cat_1",
      title: "Task Status",
      items: [
        { id: 1, name: "Completed" },
        { id: 2, name: "In Progress" },
        { id: 3, name: "Not Started" },
      ],
    },
    {
      id: "cat_2",
      title: "Task Priority",
      items: [
        { id: 1, name: "Extreme" },
        { id: 2, name: "Moderate" },
        { id: 3, name: "Low" },
      ],
    },
  ]);

  const handleCreateCategory = (title) => {
    const newCategory = {
      id: `cat_${Date.now()}`,
      title: title,
      items: [],
    };
    setCategories([...categories, newCategory]);
    setIsCreatingCategory(false);
  };

  const handleDeleteFullCategory = (categoryId) => {
    setCategories(categories.filter((cat) => cat.id !== categoryId));
  };

  const handleDeleteItem = (categoryId, itemId) => {
    setCategories(
      categories.map((cat) => {
        if (cat.id === categoryId) {
          return {
            ...cat,
            items: cat.items.filter((item) => item.id !== itemId),
          };
        }
        return cat;
      })
    );
  };

  const renderContent = () => {
    switch (activeId) {
      case 1:
        return <DashboardContent />;
      case 2:
        return <VitalTask />;
      case 3:
      case 4:
        if (isCreatingCategory) {
          return (
            <CreateCategory
              onCreate={handleCreateCategory}
              onCancel={() => setIsCreatingCategory(false)}
            />
          );
        }
        return (
          <TaskCategories
            categories={categories}
            onDeleteCategory={handleDeleteFullCategory}
            onDeleteItem={handleDeleteItem}
            onAddCategoryClick={() => setIsCreatingCategory(true)}
            onGoBack={() => setActiveId(1)}
          />
        );
      default:
        return (
          <div className="empty-state">
            <h1>Сторінка "{activeId}" у розробці</h1>
          </div>
        );
    }
  };

  return (
    <div className="main-page">
      <Header />
      <div className="main-content">
        <Sidebar activeId={activeId} setActiveId={setActiveId} />

        {renderContent()}
      </div>
    </div>
  );
};

export default Main;
